// Validate Retell webhook signature
// Retell sends X-Retell-Signature: sha256=<hmac>
const crypto = require('crypto');
const secret = $env.RETELL_API_KEY;
const sigHeader = $input.first().headers['x-retell-signature'] ?? '';
const rawBody = JSON.stringify($input.first().body);

// HMAC-SHA256 validation
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
if (sigHeader && sigHeader !== expected) {
  throw new Error('Retell signature mismatch — possible replay attack');
}

const payload = $input.first().body;

// Only handle on-call-ended events
if (payload.event !== 'call_ended') {
  return [{ json: { skip: true, reason: `Event ${payload.event} not call_ended` } }];
}

const call = payload.call ?? {};
const callId = call.call_id ?? payload.call_id;
const agentId = call.agent_id ?? null;

// Determine client_id from agent metadata
const clientId = call.metadata?.client_id ?? null;

if (!clientId) {
  return [{ json: { skip: true, reason: 'No client_id in call metadata — not an agency intake call' } }];
}

return [{
  json: {
    skip: false,
    call_id: callId,
    agent_id: agentId,
    client_id: clientId,
    duration_seconds: call.duration_ms ? Math.round(call.duration_ms / 1000) : 0,
    ended_reason: call.ended_reason ?? 'unknown',
    recording_url: call.recording_url ?? null,
    transcript_available: !!call.transcript
  }
}];
